-- Backfill server.jar SHA1 (+ URL) for versions ingested before the ledger tracked them.
-- Values fetched from Mojang's version metadata at authoring time; a released jar is immutable,
-- so these are the SHAs of the data already in the tables. Guarded on server_jar_sha IS NULL so
-- it only fills blanks and never clobbers a value a later run recorded. Versions absent here
-- (environment drift) stay NULL and are simply skipped by the freshness check. See MCO-168.
UPDATE minecraft_version_ingestion SET server_jar_sha = '3cf24a8694aca6267883b17d934efacc5e44440d', server_jar_url = 'https://piston-data.mojang.com/v1/objects/3cf24a8694aca6267883b17d934efacc5e44440d/server.jar' WHERE version = '1.18.0' AND server_jar_sha IS NULL;
